#include<cstdio>
#include<algorithm>
#include<cstring>
#define rep(a,b,c) for(int c(a);c<=(b);++c)
#define drep(a,b,c) for(int c(a);c>=(b);--c)
inline int read()
{
	int res=0;char ch=getchar();while(ch<'0'||ch>'9')ch=getchar();
	while(ch<='9'&&ch>='0')res=res*10+(ch^48),ch=getchar();return res;
}
template<typename T> inline T min(const T&x,const T&y){return x<y?x:y;}
template<typename T> inline T max(const T&x,const T&y){return x<y?y:x;}
template<typename T> inline void chkmin(T&x,const T&w){w<x?x=w:T();}
template<typename T> inline void chkmax(T&x,const T&w){x<w?x=w:T();}
const int N=1e5+10,INF=0x3f3f3f3f; struct node{int a,b,c;}t[N];int n,h[N],v[N],Ph[N],Pv[N],ph,pv;double g1[N];int f1[N];
inline int bndh(const int &k){int l(1),r(ph),m;while(l<=r)Ph[m=(l+r)>>1]<=k?l=m+1:r=m-1;return l-1;}
inline int bndv(const int &k){int l(1),r(pv),m;while(l<=r)Pv[m=(l+r)>>1]<=k?l=m+1:r=m-1;return l-1;}
inline bool cmpa(const node&x,const node&y){return x.a==y.a?(x.b==y.b?x.c<y.c:x.b<y.b):x.a<y.a;}
inline bool cmpb(const node&x,const node&y){return x.b==y.b?x.c<y.c:x.b<y.b;}
struct Pair
{
	int dp;double g;inline Pair(const int &D=-INF,const double G=1){dp=D;g=G;}
	inline Pair operator +(const Pair &Q)const{if(dp<Q.dp)return Q;if(dp>Q.dp)return Pair(dp,g);return dp?Pair(dp,Q.g+g):Pair(0,1);}
}dp[N];
namespace Seg
{
	int idx[N];Pair sm[N<<2];
	inline void update(const int &x){sm[x]=sm[x<<1]+sm[x<<1|1];}
	inline void build(const int &l=1,const int &r=pv,const int &cur=1)
	{
		if(l==r){idx[l]=cur;return;}const int &mid=(l+r)>>1;
		build(l,mid,cur<<1); build(mid+1,r,cur<<1|1); update(cur);
	}
	inline Pair qry(const int &qr,const int &l=1,const int &r=pv,const int &cur=1)
	{
		if(r==qr)return sm[cur];const int &mid=(l+r)>>1;
		if(qr<=mid)return qry(qr,l,mid,cur<<1);return qry(mid,l,mid,cur<<1)+qry(qr,mid+1,r,cur<<1|1);
	}
	inline void del(const int &i){int p=idx[v[i]];sm[p]=Pair();while(p>>1)update(p>>=1);}
	inline void ins(const int &i){int p=idx[v[i]];sm[p]=sm[p]+dp[i];while(p>>1)update(p>>=1);}
}
using Seg::del;using Seg::ins;using Seg::qry;
inline void cdq(const int &l,const int &r)
{
	std::sort(t+l,t+r+1,cmpa);
	if(l==r)return;const int &mid=(l+r)>>1;cdq(l,mid);
	std::sort(t+l,t+mid+1,cmpb);std::sort(t+mid+1,t+r+1,cmpb);
	int pl=l,pr=mid+1;while(pr<=r)
	{
		while(pl<=mid&&t[pl].b<=t[pr].b)ins(t[pl++].a);
		Pair tmp=qry(t[pr].c);++tmp.dp;dp[t[pr].a]=dp[t[pr].a]+tmp;++pr;
	}
	for(int i=l;i<pl;++i)del(t[i].a);cdq(mid+1,r);
}
inline void Solve(){rep(1,n,i)dp[i]=Pair(1,1); cdq(1,n);}
inline void Rev(int *a){rep(1,n>>1,i){int &x=a[i],&y=a[n-i+1],tmp=x;x=y;y=tmp;}}
int main()
{
	n=read();rep(1,n,i)h[i]=Ph[i]=read(),v[i]=Pv[i]=read();
	std::sort(Ph+1,Ph+n+1);ph=std::unique(Ph+1,Ph+n+1)-Ph-1;
	std::sort(Pv+1,Pv+n+1);pv=std::unique(Pv+1,Pv+n+1)-Pv-1;
	rep(1,n,i)h[i]=ph-bndh(h[i])+1,v[i]=pv-bndv(v[i])+1;Seg::build();
	rep(1,n,i)t[i].a=i,t[i].b=h[i],t[i].c=v[i]; Solve();
	Pair ans;rep(1,n,i)ans=ans+dp[i]; printf("%d\n",ans.dp);
	rep(1,n,i)g1[n-i+1]=dp[i].g,f1[n-i+1]=dp[i].dp,dp[i]=Pair(1,1);
	rep(1,n,i)h[i]=ph-h[i]+1,v[i]=pv-v[i]+1; Rev(h);Rev(v);
	rep(1,n,i)t[i].a=i,t[i].b=h[i],t[i].c=v[i]; Solve();
	drep(n,1,i)
	{
		if(f1[i]+dp[i].dp-1==ans.dp)printf("%.5lf ",(g1[i]*dp[i].g)/ans.g);
		else printf("0.00000 ");
	}
	return 0;
}
